/// <summary>
/// this class is extension of BankAccountStatementUIBuilder.
/// </summary>
class ETGBankAccountStatementUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGBankAccountStatementContract     bankAccountStatementContract;
    DialogField showFinancialDimension;
    DialogField financialDimensionSet;

}

Method.Source:
public void build()
{
    boolean boolFinancialDim;

    bankAccountStatementContract = this.dataContractObject();

    this.addDialogField(methodStr(ETGBankAccountStatementContract, parmBankAccount), bankAccountStatementContract);
    this.addDialogField(methodStr(ETGBankAccountStatementContract, parmFromDate), bankAccountStatementContract);
    this.addDialogField(methodStr(ETGBankAccountStatementContract, parmShowReportingCurrency), bankAccountStatementContract);
    this.addDialogField(methodStr(ETGBankAccountStatementContract, parmToDate), bankAccountStatementContract);
    this.addDialogField(methodStr(ETGBankAccountStatementContract, parmFinancialDimensions), bankAccountStatementContract);
    this.addDialogField(methodStr(ETGBankAccountStatementContract, parmFinancialDimSet), bankAccountStatementContract);

    showFinancialDimension = this.bindInfo().getDialogField(this.dataContractObject(),
        methodStr(ETGBankAccountStatementContract, parmFinancialDimensions));

    financialDimensionSet = this.bindInfo().getDialogField(this.dataContractObject(),
        methodStr(ETGBankAccountStatementContract, parmFinancialDimSet));

    if (showFinancialDimension.value())
    {
        financialDimensionSet.enabled(true);
    }
    else
    {
        financialDimensionSet.enabled(false);
    }
}

public void postBuild()
{
    super();

    showFinancialDimension.registerOverrideMethod(methodStr(FormCheckBoxControl, modified),
        methodStr(ETGBankAccountStatementUIBuilder , financialDimModified), this);
}

/// <summary>
/// 
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean financialDimModified(FormCheckBoxControl _control)
{
    if (_control.checked())
    {
        financialDimensionSet.enabled(true);
    }
    else
    {
        financialDimensionSet.enabled(false);
    }

    return true;
}
